const today = new Date();
const items = $input.all().map(i => {
  const d = i.json;
  const due = d.due_date ? new Date(d.due_date) : null;
  const overdue = due && due < today && d.status !== 'done';
  const daysUntilDue = due ? Math.ceil((due - today) / 86400000) : null;
  return { ...d, is_overdue: overdue, days_until_due: daysUntilDue };
});
const total = items.length;
const done = items.filter(i => i.status === 'done').length;
const blocked = items.filter(i => i.status === 'blocked');
const overdue = items.filter(i => i.is_overdue);
const critical_incomplete = items.filter(i => i.priority === 'critical' && i.status !== 'done');
const readiness_score = total > 0 ? Math.round((done / total) * 100) : 0;
const launch_ready = critical_incomplete.length === 0 && blocked.length === 0 && readiness_score >= 90;
return [{ json: { date: today.toISOString().slice(0,10), total, done, in_progress: items.filter(i=>i.status==='in_progress').length, blocked_count: blocked.length, overdue_count: overdue.length, critical_incomplete_count: critical_incomplete.length, readiness_score, launch_ready, blocked, overdue, critical_incomplete, all_items: items } }];

